+const std = @import("std");
+const c = @cImport({
+    @cInclude("llama.h");
+});
+
+/// Model loading options
+pub const ModelOptions = struct {
+    n_gpu_layers: i32 = 99, // Offload all layers to GPU by default
+    use_mmap: bool = true,
+    use_mlock: bool = false,
+    vocab_only: bool = false,
+};
+
+/// Context options
+pub const ContextOptions = struct {
+    n_ctx: u32 = 4096, // Context window size
+    n_batch: u32 = 512, // Batch size for prompt processing
+    n_threads: u32 = 0, // 0 = auto-detect
+};
+
+/// Generation options
+pub const GenerateOptions = struct {
+    max_tokens: u32 = 256,
+    temperature: f32 = 0.7,
+    top_p: f32 = 0.9,
+    top_k: i32 = 40,
+    repeat_penalty: f32 = 1.1,
+    on_token: ?*const fn ([]const u8) void = null,
+};
+
+/// Model info
+pub const ModelInfo = struct {
+    arch: []const u8,
+    n_params: u64,
+    n_ctx_train: u32,
+    n_embd: u32,
+    n_layer: u32,
+    n_head: u32,
+    n_vocab: u32,
+};
+
+/// Wrapper for llama_model
+pub const Model = struct {
+    handle: *c.llama_model,
+
+    const Self = @This();
+
+    pub fn load(path: []const u8, opts: ModelOptions) !Self {
+        // Initialize llama backend (once)
+        c.llama_backend_init();
+
+        var params = c.llama_model_default_params();
+        params.n_gpu_layers = opts.n_gpu_layers;
+        params.use_mmap = opts.use_mmap;
+        params.use_mlock = opts.use_mlock;
+        params.vocab_only = opts.vocab_only;
+
+        // Create null-terminated path
+        var path_buf: [4096]u8 = undefined;
+        if (path.len >= path_buf.len) return error.PathTooLong;
+        @memcpy(path_buf[0..path.len], path);
+        path_buf[path.len] = 0;
+
+        const model = c.llama_model_load_from_file(&path_buf, params);
+        if (model == null) {
+            return error.FailedToLoadModel;
+        }
+
+        return Self{ .handle = model.? };
+    }
+
+    pub fn deinit(self: *Self) void {
+        c.llama_model_free(self.handle);
+    }
+
+    pub fn getVocab(self: *const Self) *const c.llama_vocab {
+        return c.llama_model_get_vocab(self.handle).?;
+    }
+
+    pub fn getInfo(self: *const Self) ModelInfo {
+        var arch_buf: [64]u8 = undefined;
+        const arch_len = c.llama_model_meta_val_str(self.handle, "general.architecture", &arch_buf, arch_buf.len);
+        const arch = if (arch_len > 0) arch_buf[0..@intCast(arch_len)] else "unknown";
+
+        const vocab = self.getVocab();
+
+        return ModelInfo{
+            .arch = arch,
+            .n_params = c.llama_model_n_params(self.handle),
+            .n_ctx_train = @intCast(c.llama_model_n_ctx_train(self.handle)),
+            .n_embd = @intCast(c.llama_model_n_embd(self.handle)),
+            .n_layer = @intCast(c.llama_model_n_layer(self.handle)),
+            .n_head = @intCast(c.llama_model_n_head(self.handle)),
+            .n_vocab = @intCast(c.llama_vocab_n_tokens(vocab)),
+        };
+    }
+};
+
+/// Wrapper for llama_context
+pub const Context = struct {
+    handle: *c.llama_context,
+    model: *const Model,
+    sampler: *c.llama_sampler,
+
+    const Self = @This();
+
+    pub fn init(model: *const Model, opts: ContextOptions) !Self {
+        var params = c.llama_context_default_params();
+        params.n_ctx = opts.n_ctx;
+        params.n_batch = opts.n_batch;
+        params.n_threads = if (opts.n_threads == 0) @intCast(std.Thread.getCpuCount() catch 4) else @intCast(opts.n_threads);
+        params.n_threads_batch = params.n_threads;
+
+        const ctx = c.llama_init_from_model(model.handle, params);
+        if (ctx == null) {
+            return error.FailedToCreateContext;
+        }
+
+        // Create sampler chain
+        const sampler_params = c.llama_sampler_chain_default_params();
+        const sampler = c.llama_sampler_chain_init(sampler_params);
+        if (sampler == null) {
+            c.llama_free(ctx);
+            return error.FailedToCreateSampler;
+        }
+
+        return Self{
+            .handle = ctx.?,
+            .model = model,
+            .sampler = sampler.?,
+        };
+    }
+
+    pub fn deinit(self: *Self) void {
+        c.llama_sampler_free(self.sampler);
+        c.llama_free(self.handle);
+    }
+
+    pub fn generate(self: *Self, prompt: []const u8, opts: GenerateOptions) !void {
+        // Configure sampler
+        c.llama_sampler_chain_add(self.sampler, c.llama_sampler_init_temp(opts.temperature));
+        c.llama_sampler_chain_add(self.sampler, c.llama_sampler_init_top_k(opts.top_k));
+        c.llama_sampler_chain_add(self.sampler, c.llama_sampler_init_top_p(opts.top_p, 1));
+        c.llama_sampler_chain_add(self.sampler, c.llama_sampler_init_dist(c.LLAMA_DEFAULT_SEED));
+
+        const vocab = self.model.getVocab();
+
+        // Tokenize prompt
+        var tokens: [4096]c.llama_token = undefined;
+        const n_prompt_tokens = c.llama_tokenize(
+            vocab,
+            prompt.ptr,
+            @intCast(prompt.len),
+            &tokens,
+            @intCast(tokens.len),
+            true, // add_special
+            true, // parse_special
+        );
+
+        if (n_prompt_tokens < 0) {
+            return error.TokenizationFailed;
+        }
+
+        // Create batch for prompt processing
+        var batch = c.llama_batch_init(@intCast(n_prompt_tokens), 0, 1);
+        defer c.llama_batch_free(batch);
+
+        // Add prompt tokens to batch
+        for (0..@intCast(n_prompt_tokens)) |i| {
+            batch.token[i] = tokens[i];
+            batch.pos[i] = @intCast(i);
+            batch.n_seq_id[i] = 1;
+            batch.seq_id[i][0] = 0;
+            batch.logits[i] = 0;
+        }
+        batch.logits[@intCast(n_prompt_tokens - 1)] = 1; // Enable logits for last token
+        batch.n_tokens = n_prompt_tokens;
+
+        // Process prompt
+        if (c.llama_decode(self.handle, batch) != 0) {
+            return error.DecodeFailed;
+        }
+
+        // Generate tokens
+        var n_cur: usize = @intCast(n_prompt_tokens);
+        const n_ctx = c.llama_n_ctx(self.handle);
+
+        for (0..opts.max_tokens) |_| {
+            // Sample next token
+            const new_token = c.llama_sampler_sample(self.sampler, self.handle, -1);
+
+            // Check for end of generation
+            if (c.llama_vocab_is_eog(vocab, new_token)) {
+                break;
+            }
+
+            // Check context limit
+            if (n_cur >= n_ctx) {
+                break;
+            }
+
+            // Convert token to string
+            var token_buf: [128]u8 = undefined;
+            const token_len = c.llama_token_to_piece(
+                vocab,
+                new_token,
+                &token_buf,
+                @intCast(token_buf.len),
+                0,
+                true,
+            );
+
+            if (token_len > 0) {
+                const token_str = token_buf[0..@intCast(token_len)];
+                if (opts.on_token) |callback| {
+                    callback(token_str);
+                }
+            }
+
+            // Prepare batch for next token
+            batch.token[0] = new_token;
+            batch.pos[0] = @intCast(n_cur);
+            batch.n_seq_id[0] = 1;
+            batch.seq_id[0][0] = 0;
+            batch.logits[0] = 1;
+            batch.n_tokens = 1;
+
+            // Decode
+            if (c.llama_decode(self.handle, batch) != 0) {
+                return error.DecodeFailed;
+            }
+
+            n_cur += 1;
+        }
+    }
+
+    /// Get the current KV cache state (for snapshotting)
+    pub fn getKvCacheState(self: *const Self) []const u8 {
+        _ = self;
+        // TODO: Implement KV cache serialization
+        return &[_]u8{};
+    }
+
+    /// Restore KV cache state from snapshot
+    pub fn setKvCacheState(self: *Self, state: []const u8) !void {
+        _ = self;
+        _ = state;
+        // TODO: Implement KV cache deserialization
+    }
+};
+
+/// Tokenize a string into tokens
+pub fn tokenize(model: *const Model, text: []const u8, add_special: bool) ![]c.llama_token {
+    const vocab = model.getVocab();
+    var tokens: [4096]c.llama_token = undefined;
+    const n_tokens = c.llama_tokenize(
+        vocab,
+        text.ptr,
+        @intCast(text.len),
+        &tokens,
+        @intCast(tokens.len),
+        add_special,
+        true,
+    );
+
+    if (n_tokens < 0) {
+        return error.TokenizationFailed;
+    }
+
+    return tokens[0..@intCast(n_tokens)];
+}
+
+/// Convert a token to its string representation
+pub fn tokenToString(model: *const Model, token: c.llama_token) ![]const u8 {
+    const vocab = model.getVocab();
+    var buf: [128]u8 = undefined;
+    const len = c.llama_token_to_piece(
+        vocab,
+        token,
+        &buf,
+        @intCast(buf.len),
+        0,
+        true,
+    );
+
+    if (len < 0) {
+        return error.TokenConversionFailed;
+    }
+
+    return buf[0..@intCast(len)];
+}

