+const std = @import("std");
+const llama = @import("llama.zig");
+
+pub fn main() !void {
+    const allocator = std.heap.page_allocator;
+    var args = try std.process.argsWithAllocator(allocator);
+    defer args.deinit();
+
+    // Skip program name
+    _ = args.next();
+
+    const command = args.next() orelse {
+        printUsage();
+        return;
+    };
+
+    if (std.mem.eql(u8, command, "run")) {
+        const model_path = args.next() orelse {
+            std.debug.print("Error: model path required\n", .{});
+            printUsage();
+            return;
+        };
+
+        // Collect remaining args as prompt
+        var prompt_parts: std.ArrayListUnmanaged([]const u8) = .empty;
+        defer prompt_parts.deinit(allocator);
+
+        while (args.next()) |arg| {
+            try prompt_parts.append(allocator, arg);
+        }
+
+        if (prompt_parts.items.len == 0) {
+            std.debug.print("Error: prompt required\n", .{});
+            printUsage();
+            return;
+        }
+
+        const prompt = try std.mem.join(allocator, " ", prompt_parts.items);
+        defer allocator.free(prompt);
+
+        try runInference(model_path, prompt);
+    } else if (std.mem.eql(u8, command, "info")) {
+        const model_path = args.next() orelse {
+            std.debug.print("Error: model path required\n", .{});
+            return;
+        };
+        try showModelInfo(model_path);
+    } else if (std.mem.eql(u8, command, "version")) {
+        printVersion();
+    } else if (std.mem.eql(u8, command, "help")) {
+        printUsage();
+    } else {
+        std.debug.print("Unknown command: {s}\n", .{command});
+        printUsage();
+    }
+}
+
+fn runInference(model_path: []const u8, prompt: []const u8) !void {
+    std.debug.print("Loading model: {s}\n", .{model_path});
+
+    var model = llama.Model.load(model_path, .{}) catch |err| {
+        std.debug.print("Failed to load model: {}\n", .{err});
+        return err;
+    };
+    defer model.deinit();
+
+    std.debug.print("Model loaded. Creating context...\n", .{});
+
+    var ctx = try llama.Context.init(&model, .{});
+    defer ctx.deinit();
+
+    std.debug.print("Generating response for: {s}\n\n", .{prompt});
+
+    // Generate tokens
+    try ctx.generate(prompt, .{
+        .max_tokens = 256,
+        .temperature = 0.7,
+        .on_token = struct {
+            fn callback(token_str: []const u8) void {
+                // Write directly to stderr (which std.debug.print uses) for now
+                std.debug.print("{s}", .{token_str});
+            }
+        }.callback,
+    });
+
+    std.debug.print("\n\nDone.\n", .{});
+}
+
+fn showModelInfo(model_path: []const u8) !void {
+    std.debug.print("Loading model: {s}\n", .{model_path});
+
+    var model = llama.Model.load(model_path, .{}) catch |err| {
+        std.debug.print("Failed to load model: {}\n", .{err});
+        return err;
+    };
+    defer model.deinit();
+
+    const info = model.getInfo();
+
+    std.debug.print("\n", .{});
+    std.debug.print("=== Model Info ===\n", .{});
+    std.debug.print("Architecture: {s}\n", .{info.arch});
+    std.debug.print("Parameters:   {d:.2}B\n", .{@as(f64, @floatFromInt(info.n_params)) / 1_000_000_000.0});
+    std.debug.print("Context size: {d}\n", .{info.n_ctx_train});
+    std.debug.print("Embedding:    {d}\n", .{info.n_embd});
+    std.debug.print("Layers:       {d}\n", .{info.n_layer});
+    std.debug.print("Heads:        {d}\n", .{info.n_head});
+    std.debug.print("Vocab size:   {d}\n", .{info.n_vocab});
+    std.debug.print("\n", .{});
+}
+
+fn printVersion() void {
+    std.debug.print(
+        \\zell v0.1.0
+        \\
+        \\LLM inference engine built with Zig + llama.cpp
+        \\https://github.com/teamchong/zell
+        \\
+    , .{});
+}
+
+fn printUsage() void {
+    std.debug.print(
+        \\Usage: zell <command> [args]
+        \\
+        \\Commands:
+        \\  run <model> <prompt>   Run inference on a model
+        \\  info <model>           Show model information
+        \\  version                Print version info
+        \\  help                   Show this help
+        \\
+        \\Examples:
+        \\  zell run ./model.gguf "Hello, world"
+        \\  zell info ./model.gguf
+        \\
+    , .{});
+}
+
+test "basic test" {
+    // Basic sanity test
+    const x: u32 = 1;
+    const y: u32 = 2;
+    try std.testing.expect(x + y == 3);
+}
